module top_module(
    input [31:0] A,
    input [31:0] B,
    input [31:0] Cin,
    output [31:0] Sum,
    output Cout
);wire [31:0] obf_c;
    wire [31:0] s;

    assign obf_c[0] = Cin;
    genvar i;
    generate
        for (i = 0; i < 31; i = i + 1) begin
            assign s[i] = A[i] ^ B[i] ^ obf_c[i];
            assign obf_c[i+1] = (A[i] & B[i]) | (A[i] & obf_c[i]) | (B[i] & obf_c[i]);
        end
    endgenerate

    assign s[31] = A[31] ^ B[31] ^ obf_c[31];
    assign Cout = (A[31] & B[31]) | (A[31] & obf_c[31]) | (B[31] & obf_c[31]);

    assign Sum = s;

endmodule
